    max_tokens=1024,
    output_config={"format": {"type": "json_schema", "schema": schema}},
    messages=[{
        "role": "user",
        "content": "Заявка: Анна Ким (anna@corp.ru) хочет тариф Pro и просит демо.",
    }],
)

import json
data = json.loads(message.content[0].text)  # парсится всегда
print(data["plan"])  # "pro"

import { z } from "zod";
import { zodOutputFormat } from "@anthropic-ai/sdk/helpers/zod";

const Lead = z.object({
  name: z.string(),
  email: z.string(),
  plan: z.enum(["free", "pro", "enterprise"]),
  demo_requested: z.boolean(),
});

const response = await client.messages.parse({
  model: "claude-opus-4-8",
  max_tokens: 1024,
  output_config: { format: zodOutputFormat(Lead) },
  messages: [{ role: "user", content: "Заявка: Анна Ким (anna@corp.ru), тариф Pro, просит демо." }],
});

console.log(response.parsed_output?.plan); // типизировано: "free" | "pro" | "enterprise"

